var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그 유명한 사이버 캣이 이런 꼬마라니 의외로군.","JPN":"あの有名なサイバーキャットが、こんな子どもだったとは意外だ。","ENG":"I'm surprised the infamous Cyber Cat is a little girl like this.","TWN":"沒想到那個著名的駭客竟然會是這種小孩子。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"꼬마는 해킹하면 안 된다는 법 있어? 얼른 변호사나 불러 줘.","JPN":"子どもがハッキングしちゃいけないわけ？　さっさと弁護士を呼んでちょうだい。","ENG":"Little girls can hack too, you know? Just get me my lawyer.","TWN":"誰規定小孩子不能當駭客的？我勸你趕緊找個律師吧。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"애초에 꼬마든 어른이든 해킹은 하면 안 되는 법이지.","JPN":"本来、子どもだろうが大人だろうがハッキングは違法だ。","ENG":"You shouldn't be hacking, regardless of your age.","TWN":"法律可不管妳是大人還是小孩，做駭客就是違法的。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그리고 자네가 변호사와 접견할 일은 없네.","JPN":"それに、君が弁護士と接見することはない。","ENG":"And you have no need for a lawyer.","TWN":"喔對了，妳也沒必要和律師見面了呢。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"국가 안보에 중대한 위협을 끼치는 사안이라면 재판 없이 처리할 수도 있거든.","JPN":"国家安保に重大な脅威を及ぼす事案であれば、裁判を介することなく処理できるのだ。","ENG":"For matters of grave national security threats, we can process you without trial.","TWN":"對國家安全造成巨大威脅的案件，是可以跳過審判直接進行處分的。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"와, 진짜 악당 같은 소릴 하네. 국민을 이따위로 취급해도 되는 거야?","JPN":"わぁ、本物の悪党ね。国民をこんな風に扱っていいわけ？","ENG":"Wow, now you really sound like a villain. Come on, you can't treat me like this. I'm a citizen of the States!","TWN":"哇，聽起來像是個真反派在說話呢。\\n你把國民的人權當成什麼了?"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그리고 내가 무슨 큰 죄를 지었다고 거기서 국가 안보가 튀어나와?","JPN":"それに、国家安保だとか何とか言ってるけど、アタシが何をしたって言うの？","ENG":"Besides, what have I ever done to be considered a national security threat?","TWN":"我又犯了什麼滔天大罪，能夠威脅到國家安全？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그냥 심심풀이 삼아 여기저기 기웃거리고 다닌 게 다라고!","JPN":"ただ暇つぶしに、あれこれ覗きに行っただけじゃない！","ENG":"All I did was snoop around a little because I was bored!","TWN":"我只是為了打發時間到處看看而已啊！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"자신의 상황을 전혀 이해하지 못하고 있는 것 같으니 예를 하나 들어 주지.","JPN":"自身の置かれている状況を全く理解できていないようだな。では簡単に説明してやろう。","ENG":"You don't seem to understand the situation you're in at all. So let me give you an example.","TWN":"妳似乎完全沒有理解自己的處境呢，我舉個例子吧。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"최근에 자네가 침식지대에 고립되어 있던 우리 측 부대원에게 탈출 경로를 제공해 준 적이 있지?","JPN":"最近、君が侵食地帯で孤立していた我々の隊員に、脱出経路を提供したことがあるだろう？","ENG":"Remember how you helped our troops out of a Corrupted Area recently by transmitting viable waypoints for them?","TWN":"最近妳是否為困在侵蝕地區的我方部隊提供了逃脫路線？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그, 그게 뭐 어때서?","JPN":"そ、それが何だって言うのよ……","ENG":"W-what about that?","TWN":"那，那又怎樣？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"오히려 칭찬 받아야 할 일 아냐? 사람 목숨을 구해 줬잖아?","JPN":"むしろ、褒められるべきでしょ？　人の命を救ったんだから。","ENG":"If anything, shouldn't I get a medal for that? I saved lives, you know.","TWN":"你們反而應該來稱讚我吧？我可是救了人命啊！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"물론 그렇지. 그 과정에서 자네가 우리 첩보위성을 해킹하지 않았다면 말이야.","JPN":"もちろんそうだ。その過程で、君が我々の偵察衛星をハッキングしていなければな。","ENG":"Indeed. Except you hacked our ISR satellites in the process.","TWN":"確實如此。前提是妳沒有駭進我們的情報衛星裡。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아니 그건......","JPN":"いや、それは……","ENG":"But...","TWN":"不，那是……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그 외에도 수많은 기밀 자료와 정부 데이터베이스를 털어 왔더군.","JPN":"それ以外にも、多くの機密資料と政府データベースにアクセスしたようだな。","ENG":"And you also happened to break into countless classified files and the government databases.","TWN":"除此之外，妳還洩露了許多機密資料和公開了政府資料庫。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"거의 흔적이 남지 않아서 자네를 추적하는데 많은 고생을 해야 했네.","JPN":"痕跡がほぼ残っておらず、君まで辿り着くのにかなりの労力を費やした。","ENG":"It took monumental efforts tracking you down since you hardly left a trail.","TWN":"因為幾乎沒留下入侵痕跡，追蹤妳可是花了我們不少力氣。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"아주 많은 고생이었어.","JPN":"本当に苦労したよ。","ENG":"Monumental.","TWN":"非常多的力氣。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그리고 그 고생의 정도는 고스란히 자네의 형량으로 쌓이게 되겠지.","JPN":"そして、その労力の分だけ君の刑が決まるだろう。","ENG":"Likewise, the number of years you'll have to serve in prison will be equally monumental.","TWN":"但我們花的力氣越多，妳的刑罰也就越重。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래서? 고작 그런 시시한 협박이나 하러 여기까지 찾아온 거야?","JPN":"それで？　そんなつまんない脅迫をしに、ここまで来たわけ？","ENG":"So what? You came all the way here just to make a lame threat like that?","TWN":"所以呢？你來這裡的目的就是為了威脅我嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"날 잡아가고 싶다면 그냥 부하들이나 한 트럭 보냈으면 되잖아?","JPN":"アタシを捕まえたかったら、部下たちを大量に出動させればよかったんじゃないの？","ENG":"If you really wanted to arrest me, you could've just sent a truckload of your lackeys, couldn't you?","TWN":"想抓走我的話，直接把我扔進手下的車裡開走不就完事了嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"물론 나도 그렇게 하고 싶은 마음이 가득하지만......","JPN":"もちろん、私もそうしたいのは山々だったが……","ENG":"Oh, believe me. I would've loved to do that, but...","TWN":"當然，我也非常想那麼做……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"자네의 사진을 본 사령관님께서 기회를 주고 싶어하시더군.","JPN":"君の写真を見た司令官が、チャンスを与えたいとおっしゃっているのだ。","ENG":"When I showed my Commanding General your photo, she wanted to give you another chance.","TWN":"但是司令官看了妳的照片後，決定再給妳一次機會。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"기회?","JPN":"チャンス？","ENG":"A chance?","TWN":"機會？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그래, 과거의 잘못을 속죄하고 국가를 위해 헌신할 수 있는 기회.","JPN":"そうだ。過去の過ちを贖罪し、国家のために献身できるチャンスだ。","ENG":"Yes. A chance to atone for your past crimes and serve your country.","TWN":"沒錯，彌補過去的罪孽，為國家捐軀的機會。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"으웩, 말만 들어도 체할 것 같은 단어들이네.","JPN":"うえ、吐き気がする単語の羅列ね。","ENG":"Blech, every single word you just said makes me nauseous.","TWN":"哇，光聽這幾個單字我就想吐了。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"자네는 <color=#ffd34c>민간 전자전 고문</color>으로 우리 델타 세븐 부대에 합류할 수 있네.","JPN":"君は<color=#ffd34c>民間電子戦の顧問</color>として、我々デルタセブンに合流できるということだ。","ENG":"Should you accept, you will be assigned to our Delta Seven unit as a <color=#ffd34c>civilian electronic warfare consultant</color>.","TWN":"妳可以作為 <color=#ffd34c>民間電子戰顧問</color>加入我們第七三角洲部隊。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"물론 숙소는 우리가 감시할 수 있는 관사로 옮기게 될 거고 명령을 위반할 경우 군법으로 처벌받게 될 거야.","JPN":"もちろん、我々が監視できる官舎で生活することとなり、命令に背いた場合は軍法によって処罰される。","ENG":"Of course, your quarters will be relocated to a facility under our surveillance. Should you disobey any orders, you'll be court martialed in accordance with military law.","TWN":"當然，妳得搬到我們可以監視的宿舍。要是有違反命令的情況，妳將受到軍法處份。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그게 뭐야? 잡혀가는 거랑 다를 바가 없잖아?","JPN":"何それ？　囚人と何ら変わらないじゃない。","ENG":"You serious? How's that any different from going to jail?","TWN":"這算什麼？這跟坐牢沒什麼兩樣吧？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"내 말을 잘 새겨듣게.","JPN":"私の話をよく聞け。","ENG":"Listen to me closely.","TWN":"好好聽我說完。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"관타나모에 처박히게 되면 향후 200년간 자네가 다룰 수 있는 가장 최첨단의 장비는 편지지와 볼펜밖에 없을 거야.","JPN":"グアンタナモに収監されれば200年間、君が手にできる最先端装備は紙とボールペンしかないだろう。","ENG":"If we put you in Guantanamo, the most cutting edge equipment you'll get your hands on for the next 200 years will be a letter pad and a pen.","TWN":"如果妳被關進了關塔那摩監獄，那麼接下來的200年裡，妳能使用的最先進機器，就只有文具和圓珠筆。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"참고로 이 제안을 위해 사령관님께서 자네를 기소한 군 검사들을 아주 오랫동안 설득해야 했지.","JPN":"参考までにこの提案をするために司令官は、君を起訴した軍の検事たちを長時間説得し続けたのだ。","ENG":"Just so you know, the Commanding General spent many, many days convincing the military prosecutors who indicted you to make this option feasible.","TWN":"順便說一下，為了這個提案，司令官可是花了很長的時間說服那些想起訴妳的軍方檢察官。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"해커라고 해도 자신만의 윤리와 원칙을 지키는 사람이라고.","JPN":"ハッカーとはいえ、自身のモラルと原則を守っている者だとな。","ENG":"The CG insisted that even hackers have their own standards of conduct and ethics.","TWN":"她說，就算是駭客，他們也有自己的職業道德和原則之類的。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"난 자네 같은 사람을 그다지 신뢰하지 않지만, 사령관님의 말씀은 절대적이라서 말이야.","JPN":"私は君のような人間を信じていない。しかし、司令官の言葉は絶対だ。","ENG":"I don't trust the likes of you all that much, but the Commanding General's words are law around here, you see.","TWN":"我個人是不怎麼信任妳這種人，但司令官的命令是絕對的。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"지금도 우리에게 협력하는 것과 잡혀가는 것이 같다고 생각하나?","JPN":"それでも我々に協力する道と、囚人となる道が同じだと思うか？","ENG":"So, do you still think cooperating with us is no different from going to prison?","TWN":"現在還覺得跟我們合作和被抓走是一樣事情嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"후우......","JPN":"ふぅ……","ENG":"*Sigh*...","TWN":"呼……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"알겠어, 알겠다고!","JPN":"はいはい、わかったわ。","ENG":"Okay, fine!","TWN":"知道了，我知道了！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이 바닥에 정부 일 받아서 하는 녀석들이 없는 것도 아니고, 그냥 내 차례가 왔다고 치지 뭐.","JPN":"この業界には政府の仕事を引き受けてるやつらだっているわけだし、それがアタシにも回ってきたと思えばいいだけでしょ？","ENG":"It's not like I'd be the first hacker to work for the government... I guess my time has just come.","TWN":"幹這行的也不是沒有為政府效力的傢伙，這次就當作是輪到我倒楣好了。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래서, 그 사령관님 이름이 뭔데?","JPN":"それで、その司令官の名前は？","ENG":"So, what's the name of this Commanding General you're talking about?","TWN":"所以，你說的那個司令官叫什麼名字？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"사악한 해커를 위해 그렇게 애를 써 주셨으니 출근할 때 과자 선물이라도 전해 드려야겠네.","JPN":"邪悪なハッカーのために、そこまで頑張ってくれたんだから、出勤する時に手土産でも持ってかなきゃね？","ENG":"I'd better bring her a box of cookies when I show up to work since she's been so gracious to an evil hacker like me.","TWN":"居然會為了邪惡的駭客這麼努力，我至少得送點餅乾之類作禮物吧。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"마리아.","JPN":"マリアだ。","ENG":"Maria.","TWN":"瑪麗亞。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"마리아 안토노프라고 불러주게, 이웃집 아가씨.","JPN":"マリア・アントノフと呼んでくれ。隣のお嬢さん。","ENG":"It's Maria Antonov, young lady next door.","TWN":"叫瑪麗亞·安東諾夫，鄰居小姐。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아, 아줌마?!","JPN":"おっ、おばさん……！？","ENG":"Y-you're... the lady next door?!","TWN":"大、大嬸？！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그러고 보니 이웃끼리 느긋하게 차 한잔 마셔본 적이 없는 것 같네.","JPN":"そういえば、ゆっくりお茶を飲んだこともなかったな。","ENG":"Come to think of it, we never had a chance to share a pot of tea as neighbors.","TWN":"想想我們鄰居一場，似乎都沒有一起悠閒地喝過茶呢。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"음료는 내가 준비하지, 과자 선물 기대하겠네.","JPN":"飲み物は私が準備しよう。手土産、期待しているぞ。","ENG":"Bring me the cookies. I'll prepare the drink.","TWN":"我來準備飲料吧，我很期待妳送的點心。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......차는 됐어.","JPN":"……お茶は嫌い。","ENG":"Forget about the tea.","TWN":"……茶就算了。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"난 탄산음료가 좋아.","JPN":"炭酸が好きなの。","ENG":"I prefer soda.","TWN":"我喜歡碳酸飲料。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};